import { calculateEloDelta } from './task06';

describe('calculateEloDelta', () => {
  it('equal ratings, win with K=20 gives +10', () => {
    expect(calculateEloDelta(1500, 1500, 'win', 20)).toBe(10);
  });

  it('equal ratings, draw gives 0', () => {
    expect(calculateEloDelta(1500, 1500, 'draw', 20)).toBe(0);
  });

  it('higher rated player wins gives smaller delta', () => {
    const delta = calculateEloDelta(1800, 1500, 'win', 20);
    expect(delta).toBeLessThan(10);
    expect(delta).toBeGreaterThan(0);
  });

  it('lower rated player wins gives larger delta', () => {
    const delta = calculateEloDelta(1500, 1800, 'win', 20);
    expect(delta).toBeGreaterThan(10);
  });
});
